function sf_payment_provider(): string{$p=strtolower((string)(sf_get_setting('payment_provider',getenv('SF_PAYMENT_PROVIDER')?:'sandbox')?:'sandbox'));return in_array($p,['sandbox','stripe','paypal'],true)?$p:'sandbox';}
function sf_payment_mode(): string{$m=strtolower((string)(getenv('SF_PAYMENT_MODE')?:sf_get_setting('payment_mode','sandbox')?:'sandbox'));return in_array($m,['sandbox','test','live'],true)?$m:'sandbox';}
function sf_payment_provider_label(?string $p=null): string{$p=$p?:sf_payment_provider();return['sandbox'=>'Sandbox','stripe'=>'Stripe','paypal'=>'PayPal'][$p]??ucfirst($p);}
function sf_payment_secret_mask(?string $v): string{$v=(string)$v;return$v===''?'missing':substr($v,0,4).'…'.substr($v,-4);}
function sf_payment_gateway_ready(?string $p=null): bool{$p=$p?:sf_payment_provider();if($p==='sandbox')return sf_revenue_sandbox_allowed('subscription');if($p==='stripe')return(bool)(getenv('SF_STRIPE_SECRET_KEY')&&getenv('SF_STRIPE_WEBHOOK_SECRET'));return false;}
function sf_payment_absolute_url(string $path): string{$url=sf_url($path);if(preg_match('~^https?://~i',$url))return$url;$scheme=function_exists('sf_is_https')&&sf_is_https()?'https':'http';$host=sf_revenue_request_host()?:'localhost';return$scheme.'://'.$host.'/'.ltrim($url,'/');}
function sf_payment_gateway_status(): array{$p=sf_payment_provider();return['provider'=>$p,'label'=>sf_payment_provider_label($p),'ready'=>sf_payment_gateway_ready($p),'mode'=>sf_payment_mode(),'stripe_public'=>sf_get_setting('stripe_publishable_key',getenv('SF_STRIPE_PUBLISHABLE_KEY')?:''),'paypal_client_id'=>sf_get_setting('paypal_client_id',getenv('SF_PAYPAL_CLIENT_ID')?:''),'stripe_secret'=>sf_payment_secret_mask(getenv('SF_STRIPE_SECRET_KEY')?:''),'webhook_secret'=>sf_payment_secret_mask(getenv('SF_STRIPE_WEBHOOK_SECRET')?:'')];}
function sf_payment_http_post(string $url,array $fields,array $headers=[]): array{$allowed=['https://api.stripe.com/v1/checkout/sessions'];if(!in_array($url,$allowed,true))return['ok'=>false,'status'=>0,'error'=>'payment_endpoint_not_allowed','body'=>[]];if(!function_exists('curl_init'))return['ok'=>false,'status'=>0,'error'=>'curl_missing','body'=>[]];$body=http_build_query($fields);if(strlen($body)>262144)return['ok'=>false,'status'=>0,'error'=>'payment_payload_too_large','body'=>[]];$raw='';$overflow=false;$ch=curl_init($url);curl_setopt_array($ch,[CURLOPT_RETURNTRANSFER=>false,CURLOPT_POST=>true,CURLOPT_POSTFIELDS=>$body,CURLOPT_TIMEOUT=>30,CURLOPT_CONNECTTIMEOUT=>10,CURLOPT_HTTPHEADER=>$headers,CURLOPT_FOLLOWLOCATION=>false,CURLOPT_PROTOCOLS=>CURLPROTO_HTTPS,CURLOPT_REDIR_PROTOCOLS=>CURLPROTO_HTTPS,CURLOPT_SSL_VERIFYPEER=>true,CURLOPT_SSL_VERIFYHOST=>2,CURLOPT_USERAGENT=>'Stonefellow-Payments/1.0',CURLOPT_WRITEFUNCTION=>static function($curl,string $chunk)use(&$raw,&$overflow):int{if(strlen($raw)+strlen($chunk)>1048576){$overflow=true;return 0;}$raw.=$chunk;return strlen($chunk);}]);$ran=curl_exec($ch);$error=curl_error($ch);$code=(int)curl_getinfo($ch,CURLINFO_RESPONSE_CODE);curl_close($ch);if($overflow)return['ok'=>false,'status'=>$code,'error'=>'payment_response_too_large','body'=>[]];$json=json_decode($raw,true,64);$ok=$ran!==false&&$code>=200&&$code<300&&is_array($json);return['ok'=>$ok,'status'=>$code,'error'=>$error?:((string)($json['error']['message']??'')?:($code>=400?'http_'.$code:(!is_array($json)?'invalid_payment_json':''))),'body'=>is_array($json)?$json:[]];}
function sf_payment_create_stripe_checkout(array $payload): array{$secret=(string)(getenv('SF_STRIPE_SECRET_KEY')?:'');if($secret==='')return['ok'=>false,'error'=>'Missing SF_STRIPE_SECRET_KEY'];$token=(string)($payload['checkout_token']??'');$amount=max(0,(int)($payload['amount_cents']??0));$currency=strtolower(sf_revenue_normalize_currency($payload['currency']??'USD'));if(!preg_match('/^[a-f0-9]{48}$/i',$token)||$amount<=0||$currency==='')return['ok'=>false,'error'=>'Invalid checkout payload'];$fields=['mode'=>'subscription','success_url'=>sf_payment_absolute_url('billing-success.php?token='.urlencode($token).'&provider=stripe'),'cancel_url'=>sf_payment_absolute_url('billing-cancel.php?token='.urlencode($token)),'client_reference_id'=>$token,'line_items[0][quantity]'=>1,'line_items[0][price_data][currency]'=>$currency,'line_items[0][price_data][unit_amount]'=>$amount,'line_items[0][price_data][recurring][interval]'=>($payload['billing_interval']??'month')==='year'?'year':'month','line_items[0][price_data][product_data][name]'=>substr((string)($payload['plan_name']??'Stonefellow Membership'),0,190),'metadata[checkout_token]'=>$token,'subscription_data[metadata][checkout_token]'=>$token];if(!empty($payload['customer_email'])&&filter_var($payload['customer_email'],FILTER_VALIDATE_EMAIL))$fields['customer_email']=(string)$payload['customer_email'];$res=sf_payment_http_post('https://api.stripe.com/v1/checkout/sessions',$fields,['Authorization: Bearer '.$secret,'Content-Type: application/x-www-form-urlencoded','Idempotency-Key: stonefellow-sub-'.$token]);if(!$res['ok'])return['ok'=>false,'error'=>$res['error']?:'Stripe checkout creation failed','provider'=>'stripe','mode'=>sf_payment_mode()];$s=$res['body'];$id=(string)($s['id']??'');$url=(string)($s['url']??'');if($id===''||!preg_match('~^https://checkout\.stripe\.com/~',$url))return['ok'=>false,'error'=>'Stripe returned an invalid checkout session.'];return['ok'=>true,'provider'=>'stripe','provider_checkout_id'=>$id,'checkout_url'=>$url,'mode'=>sf_payment_mode(),'raw'=>sf_revenue_redact_payload($s)];}
function sf_payment_create_checkout(array $payload): array{$p=sf_payment_provider();$token=(string)($payload['checkout_token']??bin2hex(random_bytes(24)));if($p==='stripe'){if(!sf_payment_gateway_ready('stripe'))return['ok'=>false,'provider'=>'stripe','error'=>'Stripe credentials or webhook secret are not configured.'];return sf_payment_create_stripe_checkout($payload);}if($p==='paypal')return['ok'=>false,'provider'=>'paypal','error'=>'PayPal checkout is not enabled until signed webhook verification is implemented.'];if(!sf_revenue_sandbox_allowed('subscription'))return['ok'=>false,'provider'=>'sandbox','error'=>'Sandbox subscription checkout is disabled in production.'];return['ok'=>true,'provider'=>'sandbox','provider_checkout_id'=>'sandbox_checkout_'.substr(hash('sha256',$token),0,18),'checkout_url'=>(string)($payload['local_checkout_url']??''),'mode'=>'sandbox'];}
function sf_payment_extract_header(array $headers,string $name): string{$lookup=strtolower(str_replace('_','-',$name));foreach($headers as$k=>$v){$key=strtolower(str_replace('_','-',preg_replace('/^HTTP_/','',(string)$k)));if($key===$lookup)return is_array($v)?(string)reset($v):(string)$v;}return'';}
function sf_payment_verify_stripe_signature(string $raw,string $header,string $secret,int $tolerance=300): bool{if($secret===''||$header==='')return false;$parts=[];foreach(explode(',',$header)as$piece){[$k,$v]=array_pad(explode('=',trim($piece),2),2,'');$parts[$k][]=$v;}$time=(int)($parts['t'][0]??0);if(!$time||abs(time()-$time)>$tolerance)return false;$expected=hash_hmac('sha256',$time.'.'.$raw,$secret);foreach($parts['v1']??[]as$sig)if(preg_match('/^[a-f0-9]{64}$/i',$sig)&&hash_equals($expected,$sig))return true;return false;}
function sf_payment_verify_webhook(string $p,string $raw,array $headers=[]): bool{if($p==='sandbox')return!sf_revenue_is_production()&&sf_revenue_env_bool('SF_ALLOW_UNSIGNED_SANDBOX_WEBHOOKS',false);if($p==='stripe')return sf_payment_verify_stripe_signature($raw,sf_payment_extract_header($headers,'STRIPE_SIGNATURE'),getenv('SF_STRIPE_WEBHOOK_SECRET')?:'');return false;}
function sf_payment_record_gateway_event(string $p,string $type,array $payload,string $status='received',?string $error=null): void{$pdo=sf_db();if(!$pdo)return;try{$id=(string)($payload['id']??$payload['event_id']??hash('sha256',$p.$type.json_encode($payload)));if(sf_settings_table_exists('payment_gateway_webhook_events')){$stmt=$pdo->prepare("INSERT INTO payment_gateway_webhook_events (provider,provider_event_id,event_type,status,payload_json,error_message,processed_at) VALUES (?,?,?,?,?,?,NOW()) ON DUPLICATE KEY UPDATE status=VALUES(status),payload_json=VALUES(payload_json),error_message=VALUES(error_message),processed_at=NOW()");$stmt->execute([$p,substr($id,0,190),substr($type,0,120),$status,json_encode(sf_revenue_redact_payload($payload),JSON_UNESCAPED_SLASHES),$error?substr($error,0,2000):null]);}}catch(Throwable$e){error_log('Stonefellow gateway event log failed: '.$e->getMessage());}}
function sf_payment_event_object(array $p): array{$o=$p['data']['object']??$p['resource']??$p;return is_array($o)?$o:[];}
function sf_payment_checkout_token_from_event(array $p): string{$o=sf_payment_event_object($p);return(string)($o['client_reference_id']??$o['metadata']['checkout_token']??$o['subscription_details']['metadata']['checkout_token']??'');}
function sf_payment_stripe_subscription_request(string $id,bool $immediate): array{if(!preg_match('/^sub_[A-Za-z0-9_]+$/',$id))return['ok'=>false,'error'=>'invalid_subscription_reference'];$secret=(string)(getenv('SF_STRIPE_SECRET_KEY')?:'');if($secret===''||!function_exists('curl_init'))return['ok'=>false,'error'=>'stripe_runtime_unavailable'];$raw='';$overflow=false;$ch=curl_init('https://api.stripe.com/v1/subscriptions/'.rawurlencode($id));$opts=[CURLOPT_RETURNTRANSFER=>false,CURLOPT_TIMEOUT=>30,CURLOPT_CONNECTTIMEOUT=>10,CURLOPT_FOLLOWLOCATION=>false,CURLOPT_PROTOCOLS=>CURLPROTO_HTTPS,CURLOPT_REDIR_PROTOCOLS=>CURLPROTO_HTTPS,CURLOPT_SSL_VERIFYPEER=>true,CURLOPT_SSL_VERIFYHOST=>2,CURLOPT_HTTPHEADER=>['Authorization: Bearer '.$secret,'Content-Type: application/x-www-form-urlencoded'],CURLOPT_WRITEFUNCTION=>static function($c,string $chunk)use(&$raw,&$overflow):int{if(strlen($raw)+strlen($chunk)>1048576){$overflow=true;return 0;}$raw.=$chunk;return strlen($chunk);}];if($immediate)$opts[CURLOPT_CUSTOMREQUEST]='DELETE';else{$opts[CURLOPT_POST]=true;$opts[CURLOPT_POSTFIELDS]=http_build_query(['cancel_at_period_end'=>'true']);}curl_setopt_array($ch,$opts);$ran=curl_exec($ch);$error=curl_error($ch);$code=(int)curl_getinfo($ch,CURLINFO_RESPONSE_CODE);curl_close($ch);$json=json_decode($raw,true,64);$ok=!$overflow&&$ran!==false&&$code>=200&&$code<300&&is_array($json)&&(string)($json['id']??'')===$id;if($ok&&$immediate&&!empty($json['deleted']))return['ok'=>true,'state'=>'canceled'];if($ok&&!$immediate&&!empty($json['cancel_at_period_end']))return['ok'=>true,'state'=>'cancel_at_period_end'];return['ok'=>false,'error'=>$error?:((string)($json['error']['message']??'')?:'stripe_cancellation_failed')];}
function sf_payment_cancel_provider_subscription(array $s,bool $immediate=false): array{$p=(string)($s['payment_provider']??'sandbox');$ref=(string)($s['provider_subscription_id']??$s['external_subscription_id']??'');if($p==='sandbox')return sf_revenue_sandbox_allowed('subscription')?['ok'=>true,'state'=>$immediate?'canceled':'cancel_at_period_end']:['ok'=>false,'error'=>'sandbox_disabled'];if($p!=='stripe'||$ref==='')return['ok'=>false,'error'=>'provider_cancellation_unavailable'];return sf_payment_stripe_subscription_request($ref,$immediate);}
function sf_payment_process_gateway_event(string $p,string $type,array $payload): array{$pdo=sf_db();if(!$pdo)return['ok'=>false,'message'=>'No database connection.'];$o=sf_payment_event_object($payload);try{if($p==='stripe'&&$type==='checkout.session.completed'){$token=sf_payment_checkout_token_from_event($payload);if($token==='')return['ok'=>false,'message'=>'Checkout token missing.'];return sf_billing_complete_provider_checkout($token,['provider'=>'stripe','verified'=>true,'provider_payment_id'=>(string)($o['payment_intent']??$o['id']??''),'provider_subscription_id'=>(string)($o['subscription']??''),'provider_customer_id'=>(string)($o['customer']??''),'amount_cents'=>isset($o['amount_total'])?(int)$o['amount_total']:null,'currency'=>sf_revenue_normalize_currency($o['currency']??''),'payment_status'=>(string)($o['payment_status']??''),'payload'=>sf_revenue_redact_payload($payload)]);}if($p==='stripe'&&in_array($type,['customer.subscription.deleted','customer.subscription.paused'],true)){$ref=(string)($o['id']??'');if($ref!==''&&sf_settings_table_exists('user_subscriptions')){$q=$pdo->prepare('SELECT user_id FROM user_subscriptions WHERE provider_subscription_id=? OR external_subscription_id=? LIMIT 1');$q->execute([$ref,$ref]);$user=(int)$q->fetchColumn();$pdo->prepare("UPDATE user_subscriptions SET status='canceled',canceled_at=NOW(),updated_at=NOW() WHERE provider_subscription_id=? OR external_subscription_id=?")->execute([$ref,$ref]);if($user)sf_revenue_expire_subscription_grants($pdo,$user);return['ok'=>true,'message'=>'Subscription canceled.'];}}if($p==='stripe'&&$type==='invoice.payment_failed'){$ref=(string)($o['subscription']??'');if($ref!=='')$pdo->prepare("UPDATE user_subscriptions SET status='past_due',updated_at=NOW() WHERE provider_subscription_id=? OR external_subscription_id=?")->execute([$ref,$ref]);}return['ok'=>true,'message'=>'Event recorded.'];}catch(Throwable$e){error_log('Stonefellow gateway processing failed: '.$e->getMessage());return['ok'=>false,'message'=>'Gateway event processing failed.'];}}
